1481: 			len = skb->len - offset;
1482: 			/* Stop reading if we hit a patch of urgent data */
1483: 			if (tp->urg_data) {
1484: 				u32 urg_offset = tp->urg_seq - seq;
1485: 				if (urg_offset < len)
1486: 					len = urg_offset;
1487: 				if (!len)
