1489: 			}
1490: 			used = recv_actor(desc, skb, offset, len);
1491: 			if (used <= 0) {
1492: 				if (!copied)
1493: 					copied = used;
1494: 				break;
1495: 			} else if (used <= len) {
1496: 				seq += used;
1497: 				copied += used;
1498: 				offset += used;
